+import FluidAudio
+import Foundation
+
+struct DiarizationSpan: Codable, Equatable, Sendable {
+    let speakerID: String
+    let startTime: TimeInterval
+    let endTime: TimeInterval
+    var kept: Bool = false
+
+    var duration: TimeInterval {
+        max(0, endTime - startTime)
+    }
+}
+
+struct MergedDiarizationSpan: Codable, Equatable, Sendable {
+    let startTime: TimeInterval
+    let endTime: TimeInterval
+
+    var duration: TimeInterval {
+        max(0, endTime - startTime)
+    }
+}
+
+enum SpeakerFilteringFallbackReason: String, Codable, Equatable, Sendable {
+    case noUsableSpeakerSpans
+    case noSpeakerReachedThreshold
+    case insufficientKeptAudio
+    case filteredAudioExtractionFailed
+    case emptyFilteredTranscription
+}
+
+struct DiarizationSummary: Codable, Equatable, Sendable {
+    let spans: [DiarizationSpan]
+    let mergedKeptSpans: [MergedDiarizationSpan]
+    let targetSpeakerID: String?
+    let targetSpeakerDuration: TimeInterval?
+    let keptAudioDuration: TimeInterval?
+    let usedFallback: Bool
+    let fallbackReason: SpeakerFilteringFallbackReason?
+}
+
+extension DiarizationSummary {
+    func encodedString() -> String? {
+        let encoder = JSONEncoder()
+        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
+        guard let data = try? encoder.encode(self) else {
+            return nil
+        }
+
+        return String(data: data, encoding: .utf8)
+    }
+}
+
+struct SpeakerFilteringResult: Equatable, Sendable {
+    let filteredTranscript: String?
+    let summary: DiarizationSummary
+}
+
+struct SpeakerFilteringConfiguration: Equatable, Sendable {
+    var sampleRate: Double = 16_000
+    var substantialSpeakerThreshold: TimeInterval = 0.5
+    var minimumKeptAudioDuration: TimeInterval = 0.75
+    var mergeGapTolerance: TimeInterval = 0.05
+}
+
+protocol SpeakerFilteringDiarizing: AnyObject, Sendable {
+    func process(samples: [Float]) throws
+    func finalize() throws -> [DiarizationSpan]
+    func cleanup()
+}
+
+final class SpeakerFilteringLoadedModels: @unchecked Sendable {
+    let rawValue: Any
+
+    init(_ rawValue: Any) {
+        self.rawValue = rawValue
+    }
+}
+
+private enum SpeakerFilteringRuntimeError: LocalizedError {
+    case invalidLoadedModels
+
+    var errorDescription: String? {
+        switch self {
+        case .invalidLoadedModels:
+            return "Speaker filtering models could not be prepared."
+        }
+    }
+}
+
+@MainActor
+final class SpeakerFilteringRuntimeResetter: SupportingSpeechRuntimeResetting {
+    private let runtime: SpeakerFilteringRuntimeBridge
+
+    init(runtime: SpeakerFilteringRuntimeBridge) {
+        self.runtime = runtime
+    }
+
+    func resetLoadedSupportingModels() async {
+        await runtime.resetLoadedSupportingModels()
+    }
+}
+
+actor SpeakerFilteringRuntimeBridge {
+    typealias ModelLoader = @Sendable () async throws -> SpeakerFilteringLoadedModels
+    typealias DiarizerBuilder = @Sendable (SpeakerFilteringLoadedModels) throws -> any SpeakerFilteringDiarizing
+
+    private let loadModels: ModelLoader
+    private let buildDiarizer: DiarizerBuilder
+    private var cachedModels: SpeakerFilteringLoadedModels?
+
+    init(
+        loadModels: @escaping ModelLoader = {
+            let models = try await SortformerModels.loadFromHuggingFace(config: .default)
+            return SpeakerFilteringLoadedModels(models)
+        },
+        buildDiarizer: @escaping DiarizerBuilder = { loadedModels in
+            guard let models = loadedModels.rawValue as? SortformerModels else {
+                throw SpeakerFilteringRuntimeError.invalidLoadedModels
+            }
+
+            let diarizer = SortformerDiarizer(config: .default)
+            diarizer.initialize(models: models)
+            return SortformerDiarizerAdapter(diarizer: diarizer)
+        }
+    ) {
+        self.loadModels = loadModels
+        self.buildDiarizer = buildDiarizer
+    }
+
+    func makeDiarizer() async throws -> any SpeakerFilteringDiarizing {
+        let models: SpeakerFilteringLoadedModels
+        if let cachedModels {
+            models = cachedModels
+        } else {
+            let loadedModels = try await loadModels()
+            cachedModels = loadedModels
+            models = loadedModels
+        }
+
+        return try buildDiarizer(models)
+    }
+
+    func resetLoadedSupportingModels() async {
+        cachedModels = nil
+    }
+}
+
+private final class SortformerDiarizerAdapter: SpeakerFilteringDiarizing, @unchecked Sendable {
+    private let queue = DispatchQueue(label: "GhostPepper.SortformerDiarizerAdapter")
+    private var diarizer: SortformerDiarizer?
+
+    init(diarizer: SortformerDiarizer) {
+        self.diarizer = diarizer
+    }
+
+    func process(samples: [Float]) throws {
+        try queue.sync {
+            guard let diarizer else {
+                return
+            }
+
+            _ = try diarizer.process(samples: samples, sourceSampleRate: nil)
+        }
+    }
+
+    func finalize() throws -> [DiarizationSpan] {
+        try queue.sync {
+            guard let diarizer else {
+                return []
+            }
+
+            _ = try diarizer.finalizeSession()
+            let spans = Self.flattenedSpans(from: diarizer.timeline)
+            diarizer.cleanup()
+            self.diarizer = nil
+            return spans
+        }
+    }
+
+    func cleanup() {
+        queue.sync {
+            diarizer?.cleanup()
+            diarizer = nil
+        }
+    }
+
+    private static func flattenedSpans(from timeline: DiarizerTimeline) -> [DiarizationSpan] {
+        let spans = timeline.speakers
+            .sorted { lhs, rhs in
+                lhs.key < rhs.key
+            }
+            .flatMap { index, speaker in
+                speaker.finalizedSegments.map { segment in
+                    DiarizationSpan(
+                        speakerID: "Speaker \(index)",
+                        startTime: Double(segment.startTime),
+                        endTime: Double(segment.endTime)
+                    )
+                }
+            }
+
+        return spans.sorted { lhs, rhs in
+            if lhs.startTime == rhs.startTime {
+                return lhs.endTime < rhs.endTime
+            }
+
+            return lhs.startTime < rhs.startTime
+        }
+    }
+}
+
+final class SpeakerFilteringRecordingSessionCoordinator: RecordingSessionCoordinating, @unchecked Sendable {
+    private let diarizer: any SpeakerFilteringDiarizing
+    private let transcriber: any SpeechTranscribing
+    private let modelID: String
+    private let finalizer: SpeakerFilteringFinalizer
+    private let errorLogger: (String) -> Void
+    private let stateQueue = DispatchQueue(label: "GhostPepper.SpeakerFilteringRecordingSessionCoordinator")
+    private var recordedSamples: [Float] = []
+    private var isFinalized = false
+
+    init(
+        diarizer: any SpeakerFilteringDiarizing,
+        transcriber: any SpeechTranscribing,
+        modelID: String,
+        finalizer: SpeakerFilteringFinalizer = SpeakerFilteringFinalizer(),
+        errorLogger: @escaping (String) -> Void
+    ) {
+        self.diarizer = diarizer
+        self.transcriber = transcriber
+        self.modelID = modelID
+        self.finalizer = finalizer
+        self.errorLogger = errorLogger
+    }
+
+    func processAudioChunk(_ samples: [Float]) {
+        guard !samples.isEmpty else {
+            return
+        }
+
+        stateQueue.sync {
+            guard !isFinalized else {
+                return
+            }
+
+            recordedSamples.append(contentsOf: samples)
+        }
+
+        do {
+            try diarizer.process(samples: samples)
+        } catch {
+            log(error, prefix: "Speaker filtering chunk failed")
+        }
+    }
+
+    func finalize() async -> RecordingSessionFinalization {
+        let samples = stateQueue.sync {
+            isFinalized = true
+            let snapshot = recordedSamples
+            recordedSamples.removeAll(keepingCapacity: false)
+            return snapshot
+        }
+
+        defer {
+            diarizer.cleanup()
+        }
+
+        let spans: [DiarizationSpan]
+        do {
+            spans = try diarizer.finalize()
+        } catch {
+            log(error, prefix: "Speaker filtering finalization failed")
+            spans = []
+        }
+
+        let result = await finalizer.finalize(samples: samples, spans: spans) { [transcriber, modelID] keptSamples in
+            await transcriber.transcribe(samples: keptSamples, modelID: modelID)
+        }
+
+        return RecordingSessionFinalization(
+            filteredTranscript: result.filteredTranscript,
+            diarizationSummary: result.summary
+        )
+    }
+
+    private func log(_ error: Error, prefix: String) {
+        let description = error.localizedDescription
+        errorLogger(
+            "\(prefix): \(description.isEmpty ? String(describing: error) : description)"
+        )
+    }
+}
+
+struct SpeakerFilteringFinalizer: Sendable {
+    let configuration: SpeakerFilteringConfiguration
+
+    init(configuration: SpeakerFilteringConfiguration = SpeakerFilteringConfiguration()) {
+        self.configuration = configuration
+    }
+
+    func finalize(
+        samples: [Float],
+        spans: [DiarizationSpan],
+        transcribe: @escaping @Sendable ([Float]) async -> String?
+    ) async -> SpeakerFilteringResult {
+        let sortedSpans = spans.sorted { lhs, rhs in
+            if lhs.startTime == rhs.startTime {
+                return lhs.endTime < rhs.endTime
+            }
+
+            return lhs.startTime < rhs.startTime
+        }
+        let usableSpans = sortedSpans.filter { $0.duration > 0 }
+        guard !usableSpans.isEmpty else {
+            return fallbackResult(
+                spans: sortedSpans,
+                mergedKeptSpans: [],
+                targetSpeakerID: nil,
+                targetSpeakerDuration: nil,
+                keptAudioDuration: nil,
+                reason: .noUsableSpeakerSpans
+            )
+        }
+
+        var durationsBySpeaker: [String: TimeInterval] = [:]
+        for span in usableSpans {
+            durationsBySpeaker[span.speakerID, default: 0] += span.duration
+        }
+
+        guard let targetSpeakerID = usableSpans.first(where: {
+            (durationsBySpeaker[$0.speakerID] ?? 0) >= configuration.substantialSpeakerThreshold
+        })?.speakerID else {
+            return fallbackResult(
+                spans: sortedSpans,
+                mergedKeptSpans: [],
+                targetSpeakerID: nil,
+                targetSpeakerDuration: nil,
+                keptAudioDuration: nil,
+                reason: .noSpeakerReachedThreshold
+            )
+        }
+
+        let targetSpeakerDuration = durationsBySpeaker[targetSpeakerID] ?? 0
+        let keptSpans = sortedSpans.map { span in
+            var updatedSpan = span
+            updatedSpan.kept = span.speakerID == targetSpeakerID
+            return updatedSpan
+        }
+        let mergedKeptSpans = mergeKeptSpans(from: keptSpans)
+        let keptAudioDuration = mergedKeptSpans.reduce(0) { $0 + $1.duration }
+        guard keptAudioDuration >= configuration.minimumKeptAudioDuration else {
+            return fallbackResult(
+                spans: keptSpans,
+                mergedKeptSpans: mergedKeptSpans,
+                targetSpeakerID: targetSpeakerID,
+                targetSpeakerDuration: targetSpeakerDuration,
+                keptAudioDuration: keptAudioDuration,
+                reason: .insufficientKeptAudio
+            )
+        }
+
+        guard let keptSamples = extractKeptAudio(samples: samples, spans: mergedKeptSpans) else {
+            return fallbackResult(
+                spans: keptSpans,
+                mergedKeptSpans: mergedKeptSpans,
+                targetSpeakerID: targetSpeakerID,
+                targetSpeakerDuration: targetSpeakerDuration,
+                keptAudioDuration: keptAudioDuration,
+                reason: .filteredAudioExtractionFailed
+            )
+        }
+
+        let filteredTranscript = await transcribe(keptSamples)?
+            .trimmingCharacters(in: .whitespacesAndNewlines)
+        guard let filteredTranscript, !filteredTranscript.isEmpty else {
+            return fallbackResult(
+                spans: keptSpans,
+                mergedKeptSpans: mergedKeptSpans,
+                targetSpeakerID: targetSpeakerID,
+                targetSpeakerDuration: targetSpeakerDuration,
+                keptAudioDuration: keptAudioDuration,
+                reason: .emptyFilteredTranscription
+            )
+        }
+
+        return SpeakerFilteringResult(
+            filteredTranscript: filteredTranscript,
+            summary: DiarizationSummary(
+                spans: keptSpans,
+                mergedKeptSpans: mergedKeptSpans,
+                targetSpeakerID: targetSpeakerID,
+                targetSpeakerDuration: targetSpeakerDuration,
+                keptAudioDuration: keptAudioDuration,
+                usedFallback: false,
+                fallbackReason: nil
+            )
+        )
+    }
+
+    private func mergeKeptSpans(from spans: [DiarizationSpan]) -> [MergedDiarizationSpan] {
+        var mergedSpans: [MergedDiarizationSpan] = []
+
+        for span in spans where span.kept && span.duration > 0 {
+            if let lastSpan = mergedSpans.last {
+                let gap = span.startTime - lastSpan.endTime
+                if gap <= configuration.mergeGapTolerance {
+                    mergedSpans[mergedSpans.count - 1] = MergedDiarizationSpan(
+                        startTime: lastSpan.startTime,
+                        endTime: max(lastSpan.endTime, span.endTime)
+                    )
+                    continue
+                }
+            }
+
+            mergedSpans.append(
+                MergedDiarizationSpan(
+                    startTime: span.startTime,
+                    endTime: span.endTime
+                )
+            )
+        }
+
+        return mergedSpans
+    }
+
+    private func extractKeptAudio(
+        samples: [Float],
+        spans: [MergedDiarizationSpan]
+    ) -> [Float]? {
+        guard !samples.isEmpty else {
+            return nil
+        }
+
+        var keptSamples: [Float] = []
+        keptSamples.reserveCapacity(samples.count)
+
+        for span in spans {
+            let rawStartIndex = Int(floor(span.startTime * configuration.sampleRate))
+            let rawEndIndex = Int(ceil(span.endTime * configuration.sampleRate))
+            let startIndex = min(max(0, rawStartIndex), samples.count)
+            let endIndex = min(max(0, rawEndIndex), samples.count)
+            guard endIndex > startIndex else {
+                continue
+            }
+
+            keptSamples.append(contentsOf: samples[startIndex..<endIndex])
+        }
+
+        return keptSamples.isEmpty ? nil : keptSamples
+    }
+
+    private func fallbackResult(
+        spans: [DiarizationSpan],
+        mergedKeptSpans: [MergedDiarizationSpan],
+        targetSpeakerID: String?,
+        targetSpeakerDuration: TimeInterval?,
+        keptAudioDuration: TimeInterval?,
+        reason: SpeakerFilteringFallbackReason
+    ) -> SpeakerFilteringResult {
+        SpeakerFilteringResult(
+            filteredTranscript: nil,
+            summary: DiarizationSummary(
+                spans: spans,
+                mergedKeptSpans: mergedKeptSpans,
+                targetSpeakerID: targetSpeakerID,
+                targetSpeakerDuration: targetSpeakerDuration,
+                keptAudioDuration: keptAudioDuration,
+                usedFallback: true,
+                fallbackReason: reason
+            )
+        )
+    }
+}

